import React from 'react'
import { useStaticQuery, graphql } from 'gatsby'
import { Container, Card } from 'Common'
import starIcon from 'Static/icons/star.svg'
import forkIcon from 'Static/icons/fork.svg'
import { Wrapper, Grid, Item, Content, Stats } from './styles'
import bookofmoons from '../../../../static/pictures/bookofmoons.png'
import gatsbyjs from '../../../../static/pictures/gatsbyjs.png'
import poker from '../../../../static/pictures/poker.jpg'
import python from '../../../../static/pictures/python.png'
import reactnative from '../../../../static/pictures/reactnative.png'
import reactredux from '../../../../static/pictures/reactredux.png'


export const Projects = () => {
	const images = [gatsbyjs,bookofmoons,python,reactnative,reactredux,poker]
	const {
		github: {
			repositoryOwner: {
				repositories: { edges },
			},
		},
	} = useStaticQuery(graphql`
		{
			github {
				repositoryOwner(login: "paithoa") {
					repositories(
						first: 6
						orderBy: { field: STARGAZERS, direction: DESC }
					) {
						edges {
							node {
								id
								name
								url
								description
								stargazers {
									totalCount
								}
								forkCount
							}
						}
					}
				}
			}
		}
	`)
	return (
		<Wrapper as={Container} id="projects">
			<h2>Projects</h2>
			<Grid>
				{edges.map(({ node },index) => (
					<Item
						key={node.id}
						as="a"
						href={node.url}
						target="_blank"
						rel="noopener noreferrer"
					>
						<Card>
							<Content>
								<h4>{node.name}</h4>
								<p>{node.description}</p>
							</Content>
							<Stats>
								<img src={images[index]}></img>
							</Stats>
						</Card>
					</Item>
				))}
			</Grid>
		</Wrapper>
	)
}
